using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Breaking change: discriminator property renamed from "Discriminator" to "$type".
            // Keep old name so existing documents are still found.
            b.HasDiscriminator<string>("Discriminator").HasValue("Blog");

            // Breaking change: id no longer includes discriminator ("Blog|1" → "1").
            // Keep old composite format so existing documents are still found.
            b.HasDiscriminatorInJsonId();

            // Breaking change: key property now maps directly to JSON "id",
            // removing the separate "Id" JSON property that non-EF consumers may rely on.
            // Keep the old shadow-property approach so the document schema is unchanged.
            b.HasShadowId();
        });

        // Breaking change: HasIndex now throws on Cosmos (was silently ignored).
        // Removed — Cosmos indexes all properties by default.
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

